class Solution:
    def maximumLength(self, s: str) -> int:
        from collections import defaultdict

        # Step 1: Generate all special substrings and count their occurrences
        freq = defaultdict(int)
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                substr = s[i:j]
                if len(set(substr)) == 1:
                    freq[substr] += 1

        # Step 2: Filter substrings that occur at least three times
        valid_substrings = [sub for sub, count in freq.items() if count >= 3]

        # Step 3: Among those, find the longest length
        if not valid_substrings:
            return -1
        return len(max(valid_substrings, key=len))
